package com.monthlyexpo.entity;
import com.monthlyexpo.enums.*; import jakarta.persistence.*; import lombok.*; import java.math.BigDecimal; import java.time.LocalDate;
@Entity @Table(name="tractor_bookings") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder
public class TractorBooking extends BaseEntity { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(optional=false) private Customer customer; private LocalDate bookingDate; @Enumerated(EnumType.STRING) private MaterialType materialType; private Integer numberOfLoads; private BigDecimal pricePerLoad; private BigDecimal totalAmount; private BigDecimal amountPaid; private BigDecimal remainingAmount; @Enumerated(EnumType.STRING) private DeliveryStatus deliveryStatus; @Enumerated(EnumType.STRING) private PaymentStatus paymentStatus; private String remarks; public void recalculate(){ if(numberOfLoads==null) numberOfLoads=0; if(pricePerLoad==null) pricePerLoad=BigDecimal.ZERO; if(amountPaid==null) amountPaid=BigDecimal.ZERO; totalAmount=pricePerLoad.multiply(BigDecimal.valueOf(numberOfLoads)); remainingAmount=totalAmount.subtract(amountPaid); if(amountPaid.compareTo(BigDecimal.ZERO)==0) paymentStatus=PaymentStatus.UNPAID; else if(amountPaid.compareTo(totalAmount)<0) paymentStatus=PaymentStatus.PARTIAL; else { paymentStatus=PaymentStatus.PAID; remainingAmount=BigDecimal.ZERO; } if(deliveryStatus==null) deliveryStatus=DeliveryStatus.PENDING; }}
